  // Auditoría
  const handleAudChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => { setAudData(prev => ({ ...prev, [e.target.name]: e.target.value })); };
  const handleAudTableChange = (index: number, field: string, value: string) => { const newTable = [...audData.tabla]; newTable[index] = { ...newTable[index], [field]: value }; setAudData(prev => ({ ...prev, tabla: newTable })); };


