    doc.setFillColor(azulGIMA); 
    doc.roundedRect(15, 10, 22, 22, 2, 2, "F");
    doc.addImage(logoBase64, 'PNG', 17, 12, 18, 18);

    doc.setFontSize(18); doc.text("Reporte de Inventario General", 195, 20, { align: "right" }); doc.setFontSize(9); doc.setFont("helvetica", "normal"); doc.setTextColor(100); doc.text(`Corte al: ${invData.fechaCorte}`, 195, 26, { align: "right" }); doc.setDrawColor(azulGIMA); doc.setLineWidth(0.8); doc.line(15, 35, 195, 35);
