                  <div className="mb-8"><div className="bg-gima-navy text-white text-xs font-bold uppercase py-2 px-4 rounded-full mb-4 inline-block shadow-md shadow-gima-navy/20 w-full">Observaciones / Diagnósticos Inicial</div>
                    <div className="border border-slate-200 rounded-lg overflow-hidden"><table className="w-full text-sm text-left"><thead className="bg-slate-200 text-slate-700 font-bold text-xs uppercase"><tr><th className="px-4 py-3 border-r border-slate-300">Observaciones</th><th className="px-4 py-3 border-r border-slate-300">Componente</th><th className="px-4 py-3 border-r border-slate-300">¿Instalado?</th><th className="px-4 py-3 border-r border-slate-300">¿Funciona?</th><th className="px-4 py-3">Notas</th></tr></thead><tbody className="divide-y divide-slate-200">{formData.tabla.map((fila, index) => (<tr key={index}><td className="p-0"><input type="text" value={fila.obs} onChange={(e) => handleTableChange(index, 'obs', e.target.value)} className="w-full h-full px-4 py-3 outline-none hover:bg-slate-50 focus:bg-blue-50/30"/></td><td className="p-0 border-l border-slate-200"><input type="text" value={fila.comp} onChange={(e) => handleTableChange(index, 'comp', e.target.value)} className="w-full h-full px-4 py-3 outline-none hover:bg-slate-50 focus:bg-blue-50/30"/></td><td className="p-0 border-l border-slate-200"><input type="text" value={fila.inst} onChange={(e) => handleTableChange(index, 'inst', e.target.value)} className="w-full h-full px-4 py-3 outline-none hover:bg-slate-50 focus:bg-blue-50/30"/></td><td className="p-0 border-l border-slate-200"><input type="text" value={fila.func} onChange={(e) => handleTableChange(index, 'func', e.target.value)} className="w-full h-full px-4 py-3 outline-none hover:bg-slate-50 focus:bg-blue-50/30"/></td><td className="p-0 border-l border-slate-200"><input type="text" value={fila.notas} onChange={(e) => handleTableChange(index, 'notas', e.target.value)} className="w-full h-full px-4 py-3 outline-none hover:bg-slate-50 focus:bg-blue-50/30"/></td></tr>))}</tbody></table></div></div>
