                  <div className="absolute bottom-4 right-4"><button onClick={generarPDFMantenimiento} className="bg-gima-navy text-white px-2 py-1.5 rounded-full shadow-xl shadow-gima-navy/30 flex items-center gap-2 font-bold hover:scale-105 active:scale-95 transition-transform"><Printer size={12} /> Imprimir PDF</button></div>
